SELECT a.box_cd, a.box_nm, a.box_count, a.box_price, a.deposit, a.high_num, a.row_num, a.start_num, a.end_num, (SELECT COUNT(BOX_NUM) FROM BOX_info WHERE BOX_CD=a.BOX_CD AND BOX_FLAG = 'Y') use_num, (SELECT COUNT(BOX_NUM) FROM BOX_info WHERE BOX_CD=a.BOX_CD AND BOX_FLAG = 'N') req_num FROM BOX_MST a WHERE 1=1
AND a.box_nm LIKE '%' #{searchKeyword} '%'
ORDER BY BOX_CD ASC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

